@import url('https://fonts.googleapis.com/css2?family=Lexend+Deca:wght@300;400;500;600;700&family=Lora:ital,wght@0,400;0,500;0,600;1,400;1,500&display=swap');

/* ══════════════════════════════════════════════════════════════════════════
   LOGIN PAGE — Editorial Writing Platform Aesthetic
   Inspired by: Medium, Substack, and literary publication aesthetics
   ══════════════════════════════════════════════════════════════════════════ */

.auth-shell {
    display: grid;
    grid-template-columns: 1fr 1fr;
    min-height: 100svh;
    background-color: var(--bg-primary);
    color: var(--text-primary);
    font-family: var(--font-ui);
    overflow-x: hidden;
}

/* ── Left Panel: Brand Story ── */
.auth-panel {
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: center;
    padding: 64px 72px;
    background: var(--bg-card);
    border-right: 1px solid var(--border-card);
    overflow: hidden;
}

/* Decorative ink blot shapes */
.auth-panel::before {
    content: '';
    position: absolute;
    width: 400px;
    height: 400px;
    border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%;
    background: radial-gradient(
        ellipse at 30% 30%,
        rgba(212, 168, 83, 0.08),
        transparent 70%
    );
    top: -120px;
    left: -100px;
    animation: morph 20s ease-in-out infinite;
}

.auth-panel::after {
    content: '';
    position: absolute;
    width: 300px;
    height: 300px;
    border-radius: 61% 39% 47% 53% / 49% 55% 45% 51%;
    background: radial-gradient(
        ellipse at 70% 60%,
        rgba(212, 168, 83, 0.06),
        transparent 70%
    );
    bottom: -80px;
    right: 20px;
    animation: morph 25s ease-in-out infinite reverse;
}

@keyframes morph {
    0%, 100% { border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%; }
    25% { border-radius: 55% 45% 50% 50% / 60% 40% 60% 40%; }
    50% { border-radius: 40% 60% 55% 45% / 50% 55% 45% 50%; }
    75% { border-radius: 60% 40% 45% 55% / 45% 60% 40% 55%; }
}

.brand {
    font-family: "Playfair Display", serif;
    font-size: 1.1rem;
    font-weight: 600;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: var(--accent-amber);
    margin-bottom: 48px;
    position: relative;
    z-index: 1;
}

.brand::after {
    content: '';
    display: block;
    width: 32px;
    height: 2px;
    background: var(--accent-amber);
    margin-top: 16px;
    opacity: 0.5;
}

.panel-title {
    font-family: var(--font-serif);
    font-size: clamp(2rem, 4vw, 2.8rem);
    font-weight: 500;
    font-style: italic;
    max-width: 420px;
    line-height: 1.25;
    letter-spacing: -0.02em;
    margin: 0 0 24px;
    position: relative;
    z-index: 1;
    color: var(--text-heading);
}

.panel-copy {
    font-family: var(--font-serif);
    font-size: 1.1rem;
    color: var(--text-body);
    max-width: 380px;
    line-height: 1.75;
    margin: 0 0 32px;
    position: relative;
    z-index: 1;
}

.panel-details {
    display: flex;
    align-items: center;
    gap: 20px;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    color: var(--text-muted);
    letter-spacing: 0.08em;
    text-transform: uppercase;
    position: relative;
    z-index: 1;
}

.panel-details::before {
    content: '';
    display: inline-block;
    width: 4px;
    height: 4px;
    background: var(--accent-amber);
    border-radius: 50%;
    opacity: 0.6;
}

/* ── Right Panel: Form Area ── */
.auth-form-panel {
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 48px;
    background: var(--bg-primary);
}

.auth-form-card {
    width: 100%;
    max-width: 400px;
    display: flex;
    flex-direction: column;
    gap: 28px;
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    padding: 40px 36px;
    box-shadow: var(--shadow-card-sm);
    animation: slideUp 0.5s cubic-bezier(0.16, 1, 0.3, 1) both;
}

@keyframes slideUp {
    from {
        opacity: 0;
        transform: translateY(16px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.form-title {
    font-family: "Playfair Display", serif;
    font-size: 1.5rem;
    font-weight: 600;
    letter-spacing: -0.02em;
    color: var(--text-heading);
    margin-bottom: 4px;
}

.form-subtitle {
    font-family: var(--font-serif);
    color: var(--text-body);
    margin: 0;
    font-size: 0.95rem;
    font-style: italic;
    line-height: 1.5;
}

/* ── Form Styles ── */
.auth-form {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.form-field {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.form-field label {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 600;
    color: var(--text-muted);
    letter-spacing: 0.12em;
    text-transform: uppercase;
}

.auth-input {
    font-family: var(--font-ui);
    width: 100%;
    border: 1px solid var(--border-card);
    background: var(--bg-primary);
    padding: 14px 16px;
    border-radius: 8px;
    font-size: 0.95rem;
    color: var(--text-primary);
    box-sizing: border-box;
    transition:
        border-color 0.2s ease,
        box-shadow 0.2s ease,
        background-color 0.2s ease;
}

.auth-input::placeholder {
    color: var(--text-faint);
    font-style: italic;
}

.auth-input:hover {
    border-color: var(--border-light);
}

.auth-input:focus {
    outline: none;
    border-color: var(--accent-amber);
    box-shadow: 0 0 0 3px rgba(212, 168, 83, 0.12);
    background: var(--bg-primary);
}

/* Password field with toggle */
.input-with-action {
    position: relative;
    display: flex;
    align-items: center;
}

.input-with-action .auth-input {
    padding-right: 72px;
}

.show-toggle {
    position: absolute;
    right: 12px;
    background: var(--bg-pill);
    border: none;
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 600;
    letter-spacing: 0.04em;
    text-transform: uppercase;
    color: var(--text-muted);
    cursor: pointer;
    padding: 6px 10px;
    border-radius: 4px;
    transition:
        background-color 0.15s ease,
        color 0.15s ease;
}

.show-toggle:hover {
    background: var(--bg-hover);
    color: var(--accent-amber);
}

.show-toggle:focus-visible {
    outline: 2px solid var(--accent-amber);
    outline-offset: 2px;
}

/* ── Buttons ── */
.primary-button {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    width: 100%;
    padding: 14px 20px;
    border-radius: 8px;
    border: none;
    background: var(--text-heading);
    color: var(--bg-primary);
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 600;
    letter-spacing: 0.02em;
    cursor: pointer;
    transition:
        transform 0.15s ease,
        box-shadow 0.2s ease,
        background-color 0.2s ease;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

.primary-button:hover:not(:disabled) {
    transform: translateY(-1px);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
}

.primary-button:active:not(:disabled) {
    transform: translateY(0);
}

.primary-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    box-shadow: none;
}

.button-label {
    display: inline-block;
}

.button-spinner {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-top-color: #fff;
    animation: spin 0.7s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

.secondary-button {
    width: 100%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 13px 18px;
    border-radius: 8px;
    border: 1px solid var(--border-card);
    background: transparent;
    color: var(--text-secondary);
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 500;
    cursor: pointer;
    transition:
        border-color 0.2s ease,
        background-color 0.2s ease,
        color 0.2s ease;
}

.secondary-button:hover:not(:disabled) {
    border-color: var(--accent-amber);
    background: rgba(212, 168, 83, 0.04);
    color: var(--accent-amber);
}

.secondary-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ── Footer Link ── */
.auth-footer {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    padding-top: 8px;
    border-top: 1px solid var(--border-card);
    color: var(--text-muted);
    font-size: 0.85rem;
}

.link-button {
    background: none;
    border: none;
    color: var(--accent-amber);
    font-family: var(--font-ui);
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    padding: 0;
    transition: color 0.15s ease;
}

.link-button:hover {
    color: var(--text-heading);
    text-decoration: underline;
    text-underline-offset: 3px;
}

.link-button:focus-visible {
    outline: 2px solid var(--accent-amber);
    outline-offset: 2px;
    border-radius: 4px;
}

/* ── Messages ── */
.form-message {
    padding: 12px 14px;
    border-radius: 8px;
    font-family: var(--font-ui);
    font-size: 0.85rem;
    font-weight: 500;
    border: 1px solid transparent;
    animation: fadeIn 0.3s ease;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

.form-message.error {
    background: var(--color-danger-bg);
    color: var(--color-danger);
    border-color: rgba(220, 38, 38, 0.2);
}

.form-message.success {
    background: var(--color-success-bg);
    color: var(--color-success);
    border-color: rgba(22, 163, 74, 0.2);
}

/* ══════════════════════════════════════════════════════════════════════════
   RESPONSIVE BREAKPOINTS
   ══════════════════════════════════════════════════════════════════════════ */

@media (prefers-reduced-motion: reduce) {
    .auth-form-card {
        animation: none;
    }
    .auth-panel::before,
    .auth-panel::after {
        animation: none;
    }
    .primary-button,
    .secondary-button,
    .auth-input,
    .show-toggle {
        transition: none;
    }
}

@media (max-width: 1024px) {
    .auth-shell {
        display: flex;
        flex-direction: column;
        min-height: 100svh;
        height: auto;
    }

    .auth-panel {
        flex-shrink: 0;
        padding: 48px 40px;
        border-right: none;
        border-bottom: 1px solid var(--border-card);
    }

    .panel-title {
        font-size: 2rem;
        max-width: 100%;
    }

    .panel-copy {
        max-width: 100%;
    }

    .auth-form-panel {
        flex: 1;
        padding: 40px 24px 56px;
    }

    .auth-form-card {
        max-width: 100%;
        box-shadow: none;
        background: transparent;
        border: none;
        padding: 0;
    }
}

@media (max-width: 600px) {
    .auth-shell {
        min-height: auto;
    }

    .auth-panel {
        padding: 36px 24px;
    }

