file.content:
.settings-page {
    max-width: 520px;
    margin: 0 auto;
    padding: 32px 20px 64px;
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.settings-header {
    display: flex;
    align-items: center;
    gap: 12px;
}

.settings-back-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 8px;
    border: 1px solid var(--border-card);
    background: var(--bg-card);
    color: var(--text-secondary);
    cursor: pointer;
    transition: border-color 0.2s ease, color 0.2s ease;
}

.settings-back-btn:hover {
    border-color: var(--accent-amber);
    color: var(--accent-amber);
}

.settings-title {
    font-family: "Playfair Display", serif;
    font-size: 1.4rem;
    font-weight: 600;
    letter-spacing: -0.02em;
    color: var(--text-heading);
    margin: 0;
}

.settings-section {
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    padding: 28px 24px;
    display: flex;
    flex-direction: column;
    gap: 16px;
    box-shadow: var(--shadow-card-sm);
}

.settings-section-title {
    font-family: var(--font-ui);
    font-size: 0.95rem;
    font-weight: 600;
    color: var(--text-heading);
    margin: 0;
    padding-bottom: 12px;
    border-bottom: 1px solid var(--border-card);
}

.settings-current-value {
    font-family: var(--font-ui);
    font-size: 0.85rem;
    color: var(--text-muted);
    margin: 0;
}

.settings-current-value strong {
    color: var(--text-secondary);
    font-weight: 500;
}

.settings-form {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.settings-field {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.settings-field label {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 600;
    color: var(--text-muted);
    letter-spacing: 0.12em;
    text-transform: uppercase;
}

/* Reuse auth-input, input-with-action, show-toggle, primary-button,
   button-label, button-spinner, form-message from login.css */

@media (max-width: 600px) {
    .settings-page {
        padding: 20px 16px 48px;
    }

    .settings-section {
        padding: 20px 16px;
    }

    .settings-title {
        font-size: 1.2rem;
    }
}

